@codyde 

```python
from flask import Flask
from flask_ask import Ask, statement, session, delegate


app = Flask("TestSkill")
ask = Ask(app, "/skill")


COMPLETED_DIALOG_STATE = 'COMPLETED'

def get_dialog_state():
    return session['dialogState']


@ask.intent('HelloIntent')
def hello(param1, param2, param3):
    # delegate dialog to Alexa until all parameters are set
    dialog_state = get_dialog_state()
    if dialog_state != COMPLETED_DIALOG_STATE:
        return delegate()

    print("parameters: #1: {}, #2: {}, #3: {}".format(param1, param2, param3))
    return statement("ok, now I've got all parameters")


if __name__ == "__main__":
    app.run(host='localhost', port=5001, debug=True)
```

